import requests

def test_update_patient_unauthorized_non_clinician():
    base_url = 'http://localhost:8080/api'
    headers = {'Authorization': 'Bearer <token_patient>'}
    patient_id = 'pat-004'

    update_payload = {
        'resourceType': 'Patient',
        'id': patient_id,
        'birthDate': '1990-01-01'
    }

    resp = requests.put(
        f'{base_url}/Patient/{patient_id}',
        json=update_payload,
        headers=headers
    )
    assert resp.status_code in [401, 403]

